"use client";

import { useCallback } from "react";
import AsciiCanvas from "./AsciiCanvas";
import { CELL_H, CELL_W } from "@/lib/ascii/shapeVectors";

/**
 * Compact live 3D ASCII doorway / portal arch, rendered one per open
 * question on the `/open-questions` page.
 *
 * Conceit: an open question is an unresolved coherence tension between
 * two claims. Visually, that's a threshold — a doorway the firm hasn't
 * yet crossed. Each portal is:
 *
 *   - Two columns (Doric simplification — just vertical bars with a
 *     capital and a base).
 *   - An arch across the top made of stacked stones.
 *   - A shimmering inside — a procedural noise band that pulses with the
 *     question's severity.
 *
 * `severity` (0..1) controls:
 *   - the amplitude of the shimmer
 *   - the amber saturation of the arch
 *   - the thickness of the column highlights
 *
 * The geometry is 2D-projected-from-3D (narrow pitch, slow yaw) so the
 * ASCII picker gets proper shape cues for the curved arch rather than
 * just horizontal bars.
 */

export type OpenQuestionPortalProps = {
  /** 0..1 — drives shimmer amplitude and brightness. */
  severity?: number;
  cols?: number;
  rows?: number;
  /** An animation-phase offset so a column of portals don't all pulse in lockstep. */
  phase?: number;
  ariaLabel?: string;
};

export default function OpenQuestionPortal({
  severity = 0.5,
  cols = 24,
  rows = 10,
  phase = 0,
  ariaLabel = "Open question portal",
}: OpenQuestionPortalProps) {
  const S = Math.max(0, Math.min(1, severity));
  const width = cols * CELL_W;
  const height = rows * CELL_H;

  const render = useCallback(
    (ctx: CanvasRenderingContext2D, timeMs: number) => {
      const t = timeMs / 1000 + phase;
      ctx.clearRect(0, 0, width, height);

      const cx = width / 2;
      const baseY = height * 0.88;
      const topY = height * 0.08;

      // ── Columns (two vertical bars with capitals). The highlight intensity
      //    rises with severity so "hotter" questions feel more lit.
      const colBrightness = 0.55 + S * 0.45;
      ctx.strokeStyle = `rgba(255, 220, 160, ${colBrightness})`;
      ctx.lineWidth = 2.2;
      const colXL = width * 0.18;
      const colXR = width * 0.82;
      const capH = height * 0.09;

      for (const cxEdge of [colXL, colXR]) {
        // Shaft
        ctx.beginPath();
        ctx.moveTo(cxEdge, baseY);
        ctx.lineTo(cxEdge, topY + capH);
        ctx.stroke();
        // Capital (wider horizontal mark + stylobate at the base)
        ctx.beginPath();
        ctx.moveTo(cxEdge - 5, topY + capH);
        ctx.lineTo(cxEdge + 5, topY + capH);
        ctx.moveTo(cxEdge - 6, baseY);
        ctx.lineTo(cxEdge + 6, baseY);
        ctx.stroke();
      }

      // ── Arch: a series of stacked stone segments across the top.
      //    Each "stone" is a short chord of the semi-circle, drawn as a
      //    tiny trapezoid so the ASCII picker reads discrete blocks.
      const archY = topY + capH;
      const archW = colXR - colXL;
      const archR = archW / 2;
      const stones = 9;
      ctx.strokeStyle = `rgba(255, 200, 120, ${0.7 + S * 0.3})`;
      ctx.lineWidth = 1.6;
      for (let k = 0; k < stones; k++) {
        const t0 = Math.PI - (k / stones) * Math.PI;
        const t1 = Math.PI - ((k + 1) / stones) * Math.PI;
        const x0 = cx + Math.cos(t0) * archR;
        const y0 = archY - Math.sin(t0) * archR * 0.55; // squash vertically
        const x1 = cx + Math.cos(t1) * archR;
        const y1 = archY - Math.sin(t1) * archR * 0.55;
        ctx.beginPath();
        ctx.moveTo(x0, y0);
        ctx.lineTo(x1, y1);
        ctx.stroke();
        // Radial joint line — suggests the gap between stones.
        ctx.beginPath();
        ctx.moveTo(x0, y0);
        ctx.lineTo(x0 + (cx - x0) * 0.08, y0 + (archY - y0) * 0.08);
        ctx.stroke();
      }

      // ── Interior shimmer: a vertical band of horizontal filaments whose
      //    brightness oscillates with time + severity, suggesting heat
      //    haze or portal-energy rippling inside the threshold.
      const innerL = colXL + 6;
      const innerR = colXR - 6;
      const innerTop = archY + 2;
      const innerBot = baseY - 2;
      const filaments = 6;
      for (let i = 0; i < filaments; i++) {
        const u = i / (filaments - 1);
        const y = innerTop + (innerBot - innerTop) * u;
        const pulse = Math.sin(t * 2.4 + i * 0.7 + phase) * 0.5 + 0.5;
        const a = 0.25 + S * 0.4 * pulse;
        ctx.strokeStyle = `rgba(255, 180, 80, ${a})`;
        ctx.lineWidth = 1 + S * 0.8;
        ctx.beginPath();
        const waveOff = Math.sin(t * 1.6 + i * 1.1) * 2;
        ctx.moveTo(innerL + waveOff, y);
        ctx.lineTo(innerR + waveOff, y);
        ctx.stroke();
      }

      // ── Keystone mark at the top of the arch. A small filled diamond
      //    gives the composition a focal point and reads as a bright
      //    glyph after ASCII conversion.
      const keyY = archY - archR * 0.55;
      const keyR = 3 + S * 1.5;
      ctx.fillStyle = `rgba(255, 230, 180, ${0.7 + S * 0.3})`;
      ctx.beginPath();
      ctx.moveTo(cx, keyY - keyR);
      ctx.lineTo(cx + keyR, keyY);
      ctx.lineTo(cx, keyY + keyR);
      ctx.lineTo(cx - keyR, keyY);
      ctx.closePath();
      ctx.fill();
    },
    [width, height, S, phase],
  );

  return (
    <AsciiCanvas
      cols={cols}
      rows={rows}
      render={render}
      contrast={1.7}
      ariaLabel={ariaLabel}
    />
  );
}

  @@index([organizationId])
  @@index([organizationId, methodName, methodVersion, methodDomain, observedAt])
  @@index([targetKind, observedAt])
}

// ── ResearchSuggestion — mirrors noosphere.models.ResearchSuggestion ───────

model ResearchSuggestion {
  id             String @id @default(cuid())
  organizationId String

  noosphereId  String?  @unique
  title        String
  summary      String   @default("")
  rationale    String   @default("")
  readingUris  String   @default("[]") // JSON string[]
  sessionLabel String   @default("")
  createdAt    DateTime @default(now())

  // ── Source tracking ───────────────────────────────────────────────
  // The upload whose ingestion run generated this suggestion. Unlike
  // Conclusion, ResearchSuggestion is NOT deduplicated across uploads
  // — if two uploads both happen to prompt the same "read X" suggestion
  // they each get their own row. When the source upload is deleted
  // the suggestion goes with it.
  sourceUploadId String?
  sourceUpload   Upload? @relation("ResearchSuggestionSourceUpload", fields: [sourceUploadId], references: [id])

  suggestedForFounderId String?
  suggestedForFounder   Founder?     @relation(fields: [suggestedForFounderId], references: [id])
  organization          Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([sourceUploadId])
}

// ── ReviewItem — mirrors noosphere.models.ReviewItem (+ portal resolution) ─

model ReviewItem {
  id             String @id @default(cuid())
  organizationId String

  noosphereId       String?   @unique
  claimAId          String
  claimBId          String
  reason            String    @default("")
  layerVerdictsJson String    @default("{}") // dict str -> str
  severity          Float     @default(0)
  status            String    @default("open") // open | done | dismissed
  aggregatorVerdict String?
  priorScoresJson   String?
  humanVerdict      String?
  humanOverrule     Boolean   @default(false)
  resolutionNote    String    @default("")
  createdAt         DateTime  @default(now())
  resolvedAt        DateTime?

  resolvedByFounderId String?
  resolvedByFounder   Founder?     @relation("ReviewResolver", fields: [resolvedByFounderId], references: [id])
  organization        Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
}

// ── OpenQuestionCandidate — mirrors conclusions.OpenQuestionCandidate ───────

model OpenQuestion {
  id             String @id @default(cuid())
  organizationId String

  noosphereId              String?  @unique
  summary                  String
  claimAId                 String
  claimBId                 String
  unresolvedReason         String   @default("")
  layerDisagreementSummary String   @default("")
  createdAt                DateTime @default(now())

  // ── Source tracking ───────────────────────────────────────────────
  // The upload whose ingestion produced this open question. Cascaded
  // with the upload's soft-delete; also disappears if either of its
  // referenced Conclusions has been orphan-deleted (a question about
  // a claim that no longer exists in the Codex has no meaning).
  sourceUploadId String?
  sourceUpload   Upload? @relation("OpenQuestionSourceUpload", fields: [sourceUploadId], references: [id])

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([sourceUploadId])
}

model AuditEvent {
  id             String   @id @default(cuid())
  organizationId String
  founderId      String
  uploadId       String?
  action         String
  detail         String?
  createdAt      DateTime @default(now())

  founder      Founder      @relation(fields: [founderId], references: [id])
  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  upload       Upload?      @relation(fields: [uploadId], references: [id], onDelete: SetNull)

  @@index([organizationId])
}

// ── Belief revision audit ledger ─────────────────────────────────────────
//
// Every committed revision (founder marks new evidence on a claim and
// confirms the propagation preview) appends one row here. The
// `preConfidenceSnapshot` is what makes time-replay work: replaying the
// ledger up to but not including a given event reconstructs the prior
// belief state exactly. `revertedAt` is the soft-delete: the public
// "/revisions/<id>" page renders an event regardless, but conclusion
// readers fall through to the previous non-reverted event.
model RevisionEvent {
  id             String @id @default(cuid())
  organizationId String
  /// Plan id from the noosphere engine (sha256 over inputs+thresholds);
  /// duplicates indicate idempotent re-submits and are allowed.
  planId         String
  /// Founder who confirmed the revision in the preview modal.
  founderId      String

  /// JSON: [{ claim_id, weight, new_evidence }] — the RevisionInput batch.
  inputsJson            String
  /// JSON: full RevisionPlan.to_dict() — frozen at commit time.
  planJson              String
  /// JSON: { conclusion_id: confidence_before } — the before-snapshot.
  preConfidenceSnapshot String
  /// Conclusions whose confidence changed by > δ at commit time. Stored
  /// as a denormalised JSON array of conclusion ids so the UI can build
  /// the "updated" pill query without parsing planJson on every page
  /// render. Source of truth is still planJson.
  affectedConclusionIds String @default("[]")

  /// `true` when the founder typed the K-cap confirmation phrase. Always
  /// `false` for revisions whose affected_count <= K; informational only.
  typedConfirmation Boolean @default(false)

  createdAt  DateTime  @default(now())
  revertedAt DateTime?

  founder      Founder      @relation(fields: [founderId], references: [id])
  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])

from __future__ import annotations

import contextvars
import hashlib
import json
import logging
import os
import subprocess
from datetime import datetime, timezone
from functools import wraps
from typing import Any, Callable
from uuid import uuid4

from pydantic import BaseModel

from noosphere.models import (
    CascadeEdgeRelation,
    Method,
    MethodImplRef,
    MethodInvocation,
    MethodType,
)
from noosphere.methods._hooks import _FAILURE_HOOKS, _POST_HOOKS, _PRE_HOOKS
from noosphere.methods._registry import REGISTRY
from noosphere.methods.composition import validate_depends_on
from noosphere.methods.domain_bounds import DomainBound, load_domain_bound

logger = logging.getLogger(__name__)

CORRELATION_ID: contextvars.ContextVar[str] = contextvars.ContextVar(
    "CORRELATION_ID", default=""
)
TENANT_ID: contextvars.ContextVar[str] = contextvars.ContextVar(
    "TENANT_ID", default="default"
)

_store_factory: Callable[..., Any] | None = None


def set_store_factory(factory: Callable[..., Any]) -> None:
    global _store_factory
    _store_factory = factory


def _get_store() -> Any:
    if _store_factory is not None:
        try:
            return _store_factory()
        except Exception:
            return None
    return None


def _canonical_json(obj: Any) -> str:
    if isinstance(obj, BaseModel):
        obj = obj.model_dump(mode="json")
    return json.dumps(obj, sort_keys=True, separators=(",", ":"), default=str)


def _current_git_sha() -> str:
    sha = os.environ.get("THESEUS_GIT_SHA")
    if sha:
        return sha
    try:
        result = subprocess.run(
            ["git", "rev-parse", "HEAD"],
            capture_output=True,
            text=True,
            timeout=5,
        )
        if result.returncode == 0:
            return result.stdout.strip()
    except Exception:
        pass
    return "unknown"


def _current_correlation_id() -> str:
    return CORRELATION_ID.get()


def _current_tenant_id() -> str:
    return TENANT_ID.get()


def _validate_against_schema(schema: Any, data: Any) -> Any:
    if isinstance(schema, type) and issubclass(schema, BaseModel):
        if isinstance(data, schema):
            return data
        return schema.model_validate(data)
    if isinstance(schema, dict) and schema:
        try:
            import jsonschema as _js

            _js.validate(data, schema)
        except ImportError:
            pass
    return data


def _utcnow() -> datetime:
    return datetime.now(timezone.utc)


def _run_failure_path(
    spec: Method,
    inv: MethodInvocation,
    validated_input: Any,
    exc: BaseException,
) -> None:
    inv = inv.model_copy(
        update={
            "ended_at": _utcnow(),
            "succeeded": False,
            "error_kind": type(exc).__name__,
        }
    )
    for hook_name, hook in _FAILURE_HOOKS:
        try:
            hook(spec, inv, validated_input, exc)
        except Exception:
            logger.exception("Failure hook %s raised", hook_name)
    store = _get_store()
    if store is not None:
        try:
            store.insert_method_invocation(inv)
        except Exception:
            logger.exception("Failed to persist invocation")


def register_method(
    *,
    name: str,
    version: str,
    method_type: MethodType,
    input_schema: Any,
    output_schema: Any,
    description: str,
    rationale: str,
    preconditions: list[str] | tuple[str, ...] = (),
    postconditions: list[str] | tuple[str, ...] = (),
    dependencies: list[tuple[str, str]] | tuple[tuple[str, str], ...] = (),
    depends_on: list[str] | tuple[str, ...] = (),
    owner: str,
    status: str = "active",
    nondeterministic: bool = False,
    emits_edges: list[CascadeEdgeRelation] | tuple[CascadeEdgeRelation, ...] = (),
    domain: Any = None,
) -> Callable:
    def decorator(fn: Callable) -> Callable:
        if isinstance(input_schema, type) and issubclass(input_schema, BaseModel):
            in_schema_dict = input_schema.model_json_schema()
        elif isinstance(input_schema, dict):
            in_schema_dict = input_schema
        else:
            in_schema_dict = {}

        if isinstance(output_schema, type) and issubclass(output_schema, BaseModel):
            out_schema_dict = output_schema.model_json_schema()
        elif isinstance(output_schema, dict):
            out_schema_dict = output_schema
        else:
            out_schema_dict = {}

        impl = MethodImplRef(
            module=fn.__module__,
            fn_name=fn.__qualname__,
            git_sha=_current_git_sha(),
            image_digest=None,
        )

        spec_for_hash = {
            "name": name,
            "version": version,
            "method_type": method_type.value,
            "input_schema": in_schema_dict,
            "output_schema": out_schema_dict,
            "description": description,
            "rationale": rationale,
            "preconditions": list(preconditions),
            "postconditions": list(postconditions),
            "dependencies": [list(d) for d in dependencies],
            "implementation": impl.model_dump(mode="json"),
            "owner": owner,
            "status": status,
            "nondeterministic": nondeterministic,
        }

        method_id = hashlib.sha256(
            _canonical_json(spec_for_hash).encode()
        ).hexdigest()[:32]

        spec = Method(
            method_id=method_id,
            name=name,
            version=version,
            method_type=method_type,
            input_schema=in_schema_dict,
            output_schema=out_schema_dict,
            description=description,
            rationale=rationale,
            preconditions=list(preconditions),
            postconditions=list(postconditions),
            dependencies=list(dependencies),
            implementation=impl,
            owner=owner,
            status=status,
            nondeterministic=nondeterministic,
            created_at=_utcnow(),
        )

        @wraps(fn)
        def wrapped(input_data: Any) -> Any:
            validated_input = _validate_against_schema(input_schema, input_data)
            input_hash = hashlib.sha256(
                _canonical_json(validated_input).encode()
            ).hexdigest()

            inv = MethodInvocation(
                id=str(uuid4()),
                method_id=spec.method_id,
                input_hash=input_hash,
                output_hash="",
                started_at=_utcnow(),
                ended_at=None,
                succeeded=False,
                error_kind=None,
                correlation_id=_current_correlation_id(),
                tenant_id=_current_tenant_id(),
            )

            try:
                for _hook_name, hook in _PRE_HOOKS:
                    hook(spec, inv, validated_input)
            except Exception as e:
                _run_failure_path(spec, inv, validated_input, e)
                raise

            try:
                result = fn(validated_input)
                _validate_against_schema(output_schema, result)
                output_hash = hashlib.sha256(
                    _canonical_json(result).encode()
                ).hexdigest()
                inv = inv.model_copy(
                    update={
                        "ended_at": _utcnow(),
                        "succeeded": True,
                        "output_hash": output_hash,
                    }
                )

                for hook_name, hook in _POST_HOOKS:
                    try:
                        hook(spec, inv, validated_input, result)
                    except Exception:
                        logger.exception("Post-hook %s raised", hook_name)

                store = _get_store()
                if store is not None:
                    try:
                        store.insert_method_invocation(inv)
                    except Exception:
                        logger.exception("Failed to persist invocation")

                return result
            except Exception as e:
                _run_failure_path(spec, inv, validated_input, e)
                raise

        wrapped.__method_spec__ = spec  # type: ignore[attr-defined]

        REGISTRY.register(spec, wrapped)

        # Composition DAG: declared depends_on names must already be
        # registered. Decoration-time check so a typo fails CI rather
        # than silently leaving a ghost edge in the graph.
        if depends_on:
            validate_depends_on(
                REGISTRY.known_method_names(), name, list(depends_on)
            )
            REGISTRY.set_depends_on(name, list(depends_on))
        else:
            # Always seed the side table so build_dag() sees this node.
            REGISTRY.set_depends_on(name, [])

        if emits_edges:
            REGISTRY.set_emits_edges(method_id, list(emits_edges))

        # Domain bound is optional; when present it is normalized via the
        # deterministic loader so a bare list[str] of tags or a dict-style
        # declaration both produce the same DomainBound shape.
        if domain is not None:
            bound: DomainBound = (
                domain if isinstance(domain, DomainBound) else load_domain_bound(domain)
            )
            REGISTRY.set_domain_bound(name, bound)

        store = _get_store()
        if store is not None:
            try:
                store.insert_method(spec)
            except Exception:
                logger.exception("Failed to persist method spec")

        return wrapped

    return decorator

