import { randomUUID } from "crypto";

import { clientIpFor, fingerprintFor } from "@/lib/currentsFingerprint";
import type {
  BetsResponse,
  CalibrationResponse,
  ForecastListResponse,
  MarketListResponse,
  PortfolioSummary,
  PublicBet,
  PublicFollowupMessage,
  PublicForecast,
  PublicForecastSource,
  PublicMarket,
  PublicResolution,
} from "@/lib/forecastsTypes";

export const FORECASTS_BACKEND = (
  process.env.FORECASTS_API_URL ??
  process.env.CURRENTS_API_URL ??
  "http://127.0.0.1:8088"
).replace(/\/+$/, "");

export const FORECASTS_PROXY_TIMEOUT_MS = Number.parseInt(
  process.env.FORECASTS_PROXY_TIMEOUT_MS ?? "30000",
  10,
);

export interface ListForecastsParams {
  since?: string | Date | null;
  topic?: string | null;
  status?: string | null;
  limit?: number | null;
  seeded?: boolean | null;
}

export interface ListMarketsParams {
  source?: string | null;
  category?: string | null;
  status?: string | null;
  since?: string | Date | null;
  limit?: number | null;
}

export interface ListBetsParams {
  limit?: number | null;
  offset?: number | null;
}

type StreamingRequestInit = RequestInit & { duplex?: "half" };
type NextFetchOptions = {
  revalidate?: number | false;
  tags?: string[];
};

export interface ForecastsFetchOptions {
  cache?: RequestCache;
  next?: NextFetchOptions;
  signal?: AbortSignal;
  timeoutMs?: number;

