    select: { id: true, domain: true, methodUsed: true },
  });
  return new Map(rows.map((r) => [r.id, r as ConclusionJoin]));
}

async function buildDomainFootprints(
  organizationId: string,
  domains: Iterable<string>,
): Promise<Map<string, DomainFootprint>> {
  const out = new Map<string, DomainFootprint>();
  const unique = Array.from(new Set([...domains].filter(Boolean)));
  for (const domain of unique) {
    const count = await db.conclusion.count({
      where: { organizationId, domain, isPrediction: true, resolved: true },
    });
    out.set(domain, { domain, resolvedForecastCount: count });
  }
  return out;
}

