    textTransform: "uppercase",
    padding: "0.35rem 0.75rem",
    border: "1px solid var(--border)",
    color: "var(--parchment-dim)",
    textDecoration: "none",
  };
  const chipActive: React.CSSProperties = {
    ...chipBase,
    color: "var(--amber)",
    borderColor: "var(--amber)",
  };
  return (
    <div
      className="mono"
      style={{
        display: "flex",
        flexWrap: "wrap",
        gap: "0.4rem",
