      </span>
      <a href="/open-questions" style={active === "" ? chipActive : chipBase}>
        all
      </a>
      {options.map((d) => (
        <a
          key={d}
          href={`/open-questions?domain=${encodeURIComponent(d)}`}
          style={active === d ? chipActive : chipBase}
        >
          {d}
        </a>
      ))}
