                    gap: "0.5rem",
                    fontSize: "0.65rem",
                    letterSpacing: "0.18em",
                    textTransform: "uppercase",
                    marginBottom: "0.5rem",
                  }}
                >
                  <span>Open since {dateFmt.format(row.createdAt)}</span>
                  <span>{row.domain || "domain unspecified"}</span>
                </div>

                <p
                  style={{
                    margin: 0,
                    fontFamily: "'EB Garamond', serif",
                    fontSize: "1.05rem",
                    lineHeight: 1.55,
                  }}
                >
                  {row.summary}
                </p>

                {row.candidateMethodNames.length > 0 && (
                  <div style={{ marginTop: "0.85rem" }}>
                    <h3
                      className="mono public-muted"
                      style={{
                        fontSize: "0.65rem",
                        letterSpacing: "0.18em",
                        textTransform: "uppercase",
                        margin: "0 0 0.35rem 0",
                      }}
                    >
                      Candidate methods to address
                    </h3>
                    <ul
                      style={{
                        listStyle: "none",
                        padding: 0,
                        margin: 0,
                        display: "flex",
                        flexWrap: "wrap",
                        gap: "0.4rem",
                      }}
                    >
                      {row.candidateMethodNames.map((name) => (
                        <li key={name}>
                          <Link
                            href={`/methodology/${encodeURIComponent(name)}`}
                            className="mono"
                            style={{
                              fontSize: "0.72rem",
                              padding: "0.25rem 0.55rem",
                              border: "1px solid var(--public-rule, #ddd)",
                              borderRadius: 2,
                              textDecoration: "none",
                            }}
                          >
                            {name}
                          </Link>
                        </li>
                      ))}
                    </ul>
                  </div>
                )}

                {row.gatedPublishedConclusionIds.length > 0 && (
                  <div style={{ marginTop: "0.85rem" }}>
                    <h3
                      className="mono public-muted"
                      style={{
                        fontSize: "0.65rem",
                        letterSpacing: "0.18em",
                        textTransform: "uppercase",
                        margin: "0 0 0.35rem 0",
                      }}
                    >
                      Gated published conclusions
                    </h3>
                    <ul
                      style={{
                        listStyle: "none",
                        padding: 0,
                        margin: 0,
                        display: "flex",
                        flexWrap: "wrap",
                        gap: "0.4rem",
                      }}
                    >
                      {row.gatedPublishedConclusionIds.map((id) => (
                        <li
                          key={id}
                          className="mono"
                          style={{
                            fontSize: "0.72rem",
                            padding: "0.25rem 0.55rem",
                            border: "1px dashed var(--public-rule, #ddd)",
                            borderRadius: 2,
                            color: "var(--public-muted, #666)",
                          }}
                        >
                          {id}
                        </li>
                      ))}
                    </ul>
                  </div>
                )}
              </li>
            ))}
          </ol>
        )}
      </main>
    </>
  );
}
